const apiKey = 'YOUR_API_KEY';
let city = 'London';

function fetchWeatherData() {
    fetch(`https://api.openweathermap.org/data/2.5/forecast?q=${city}&appid=${apiKey}&units=metric`)
        .then(response => {
            if (!response.ok) throw new Error('City not found');
            return response.json();
        })
        .then(data => {
            console.log('Data retrieved successfully');
            displayForecast(data);
        })
        .catch(error => {
            console.error('Error fetching data:', error.message);
            handleCityError();
        });
}

function displayForecast(data) {
    const forecast = data.list.filter(entry => entry.dt_txt.includes('18:00:00'));
    forecast.forEach(entry => {
        const date = new Date(entry.dt * 1000);
        const high = entry.main.temp_max;
        const low = entry.main.temp_min;
        const precipitation = entry.pop * 100;
        console.log(`Date: ${date.toDateString()}, High: ${high}°C, Low: ${low}°C, Precipitation: ${precipitation}%`);
    });
}

function handleCityError() {
    console.log('Please check the city name and try again.');
}

function startWeatherMonitor() {
    fetchWeatherData();
    setInterval(fetchWeatherData, 5 * 60 * 1000);
}

startWeatherMonitor();
